// Some portions generated by Co-Pilot
"use client";

import React, {
  useRef,
  RefObject,
  useState,
  useMemo,
  useCallback,
} from "react";
import { useTranslations } from "next-intl";
import {
  useFetchReleaseNotesForVersion,
  useOnScreen,
  ReleaseNoteAPIResponse,
} from "@/hooks";
import { useSearchParams } from "next/navigation";
import "./styles.css";

export const fetchTitle = (priority: string) => {
  let title;
  switch (priority) {
    case "1":
      title =
        "P1 - Blocks development and/or testing work, production could not run.";
      break;
    case "2":
      title = "P2 - Crashes, loss of data, severe memory leak.";
      break;
    case "3":
      title = "P3 - Major loss of function.";
      break;
    case "4":
      title =
        "P4 - Minor loss of function, or other problem where easy workaround is present.";
      break;
    case "5":
      title = "P5 - Cosmetic problem like misspelt words or misaligned text.";
      break;
    case "6":
      title = "This issue is not publicly visible.";
  }
  return title;
};

export const sortReleaseNotesBy = (releaseNotes: ReleaseNoteAPIResponse) => {
  // issues/1508: Should initially be sorted by (a) priority then (b) component.
  if (releaseNotes && Array.isArray(releaseNotes.release_notes)) {
    releaseNotes.release_notes = [...releaseNotes.release_notes].sort(
      (v1, v2) => {
        let c = 0;
        if (v1.priority && v2.priority) {
          c = v1.priority.localeCompare(v2.priority);
        }
        if (c === 0 && v1.component && v2.component) {
          c = v1.component.localeCompare(v2.component);
        }
        return c;
      },
    );
  }
  return releaseNotes;
};

type SortDirection = "asc" | "desc";

interface Filters {
  priority: string;
  type: string;
  component: string;
}

const ReleaseNotesRender = () => {
  const t = useTranslations("ReleaseNotes");
  const searchParams = useSearchParams();
  const rawVersion = searchParams.get("version");
  const version = rawVersion ? rawVersion.replace(/ /g, "+") : undefined;

  const ref = useRef<HTMLDivElement | null>(null);
  const isVisible = useOnScreen(ref as RefObject<Element>, true);

  const releaseNoteDataBag = useFetchReleaseNotesForVersion(
    isVisible,
    version,
    sortReleaseNotesBy,
  );
  const releaseNotes = releaseNoteDataBag
    ? releaseNoteDataBag.releaseNoteAPIResponse
    : null;
  const releaseNotesVersion = releaseNotes ? releaseNotes.release_name : null;

  const [page, setPage] = useState(0);
  const [pageSize, setPageSize] = useState(20);
  const [sortDirection, setSortDirection] = useState<SortDirection>("asc");
  const [filters, setFilters] = useState<Filters>({
    priority: "",
    type: "",
    component: "",
  });

  // Set default type filter for jdk-xx+xx versions
  const regex = /^jdk-(2\d|\d{3,})\+\d+$/;
  const isEnhancementDefault = releaseNotesVersion?.toString
    ? regex.test(releaseNotesVersion.toString())
    : false;

  // Normalise undefined priorities to "6"
  if (releaseNotes && Array.isArray(releaseNotes.release_notes)) {
    releaseNotes.release_notes.forEach((note) => {
      if (note.priority === undefined || note.priority === null) {
        (note as { priority: string }).priority = "6";
      }
    });
  }

  // Unique values for filter dropdowns
  const { priorities, types, components } = useMemo(() => {
    const p = new Set<string>();
    const ty = new Set<string>();
    const c = new Set<string>();
    if (releaseNotes?.release_notes) {
      releaseNotes.release_notes.forEach((note) => {
        if (note.priority) p.add(note.priority);
        if (note.type) ty.add(note.type);
        if (note.component) c.add(note.component);
      });
    }
    return {
      priorities: [...p].sort(),
      types: [...ty].sort(),
      components: [...c].sort(),
    };
  }, [releaseNotes]);

  // Filter → sort → paginate
  const processedRows = useMemo(() => {
    if (!releaseNotes?.release_notes) return [];
    let rows = [...releaseNotes.release_notes];

    const activeTypeFilter =
      filters.type || (isEnhancementDefault ? "Enhancement" : "");
    if (filters.priority)
      rows = rows.filter((r) => r.priority === filters.priority);
    if (activeTypeFilter)
      rows = rows.filter((r) => r.type === activeTypeFilter);
    if (filters.component)
      rows = rows.filter((r) => r.component === filters.component);

    rows.sort((a, b) => {
      const aVal = a.priority || "";
      const bVal = b.priority || "";
      const cmp = aVal.localeCompare(bVal);
      return sortDirection === "asc" ? cmp : -cmp;
    });

    return rows;
  }, [releaseNotes, filters, sortDirection, isEnhancementDefault]);

  const totalRows = processedRows.length;
  const totalPages = Math.max(1, Math.ceil(totalRows / pageSize));
  const safePage = Math.min(page, totalPages - 1);
  const paginatedRows = processedRows.slice(
    safePage * pageSize,
    (safePage + 1) * pageSize,
  );

  const updateFilter = (field: keyof Filters, value: string) => {
    setFilters((prev) => ({ ...prev, [field]: value }));
    setPage(0);
  };

  const handleExport = useCallback(() => {
    const header = "Priority,Type,Component,Issue,Title\n";
    const csv = processedRows
      .map(
        (r) =>
          `"${r.priority || ""}","${r.type || ""}","${r.component || ""}","${r.id}","${(r.title || "").replace(/"/g, '""')}"`,
      )
      .join("\n");
    const blob = new Blob([header + csv], { type: "text/csv" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `release-notes-${releaseNotesVersion}.csv`;
    a.click();
    URL.revokeObjectURL(url);
  }, [processedRows, releaseNotesVersion]);

  const toggleSort = () => {
    setSortDirection((prev) => (prev === "asc" ? "desc" : "asc"));
  };

  const totalP1 = releaseNotes?.release_notes?.filter(
    (note) => note.priority === "1",
  ).length;

  return (
    <div
      ref={ref}
      className="release-notes-container mx-auto w-full max-w-[1400px] px-4 lg:px-8 py-6 items-center text-center justify-center"
    >
      <div className="self-stretch text-center text-lightgrey text-[20px] font-normal leading-[140%] mx-auto max-w-[860px] px-2 w-full mb-4">
        <h2 className="text-4xl font-bold text-pink mb-2 tracking-tight drop-shadow-sm">
          {releaseNotesVersion}
        </h2>
      </div>
      <div className="pt-3 w-full flex justify-center h-full">
        {!releaseNoteDataBag ? (
          <div className="flex-grow flex items-center justify-center">
            <div
              className="animate-spin rounded-full h-10 w-10 border-t-2 border-b-2 border-pink"
              aria-label="loading spinner"
            />
          </div>
        ) : (
          <div className="w-full flex-grow">
            {!releaseNotesVersion || releaseNoteDataBag?.isValid === false ? (
              <div className="bg-gradient-to-br from-[#200E46]/90 to-[#2B1A4F]/90 rounded-3xl border border-white/20 shadow-lg p-8 text-center">
                <h2 className="text-3xl font-bold text-pink tracking-tight drop-shadow-sm mb-4">
                  {t("couldnt-find-release-notes")}
                </h2>
                <span className="text-white/80 text-lg">
                  {t("not-found-helper")}{" "}
                  <code className="bg-[#14003c] px-2 py-1 rounded text-pink">
                    ?version=x.x.x
                  </code>
                </span>
              </div>
            ) : (
              <>
                <p className="release-notes-description">{t("description")}</p>
                <p className="release-notes-description">
                  <strong>{`The total number of fixes marked as P1 is: ${totalP1}`}</strong>
                </p>

                {/* Toolbar */}
                <div className="flex items-center justify-between gap-4 mb-0 bg-[#2B1A4F]/90 rounded-t-2xl border border-white/10 px-4 py-3">
                  <div className="flex items-center gap-3 flex-wrap">
                    <select
                      aria-label="Filter by priority"
                      value={filters.priority}
                      onChange={(e) => updateFilter("priority", e.target.value)}
                      className="bg-[#231146]/60 text-white/90 text-sm border border-white/10 rounded-md px-3 py-1.5 focus:outline-none focus:border-pink"
                    >
                      <option value="">All Priorities</option>
                      {priorities.map((p) => (
                        <option key={p} value={p}>
                          P{p !== "6" ? p : "?"}
                        </option>
                      ))}
                    </select>
                    <select
                      aria-label="Filter by type"
                      value={
                        filters.type ||
                        (isEnhancementDefault ? "Enhancement" : "")
                      }
                      onChange={(e) => updateFilter("type", e.target.value)}
                      className="bg-[#231146]/60 text-white/90 text-sm border border-white/10 rounded-md px-3 py-1.5 focus:outline-none focus:border-pink"
                    >
                      <option value="">All Types</option>
                      {types.map((ty) => (
                        <option key={ty} value={ty}>
                          {ty}
                        </option>
                      ))}
                    </select>
                    <select
                      aria-label="Filter by component"
                      value={filters.component}
                      onChange={(e) =>
                        updateFilter("component", e.target.value)
                      }
                      className="bg-[#231146]/60 text-white/90 text-sm border border-white/10 rounded-md px-3 py-1.5 focus:outline-none focus:border-pink"
                    >
                      <option value="">All Components</option>
                      {components.map((c) => (
                        <option key={c} value={c}>
                          {c}
                        </option>
                      ))}
                    </select>
                  </div>
                  <button
                    onClick={handleExport}
                    className="text-sm font-medium text-white/80 hover:text-white bg-[#231146]/60 border border-white/10 rounded-md px-4 py-1.5 hover:bg-[#231146] transition-colors"
                  >
                    Export CSV
                  </button>
                </div>

                {/* Table */}
                <div className="overflow-x-auto rounded-b-2xl border border-t-0 border-white/10 bg-[#231146]/50 backdrop-blur-sm shadow-lg">
                  <table
                    className="w-full text-left"
                    aria-label="Release Notes"
                  >
                    <thead>
                      <tr className="bg-[#2B1A4F]/98 border-b-2 border-pink/40">
                        <th
                          className="px-4 py-3 text-white font-bold text-xs uppercase tracking-wider cursor-pointer select-none hover:text-pink transition-colors w-[120px]"
                          onClick={toggleSort}
                        >
                          Priority{" "}
                          {sortDirection === "asc" ? "\u25B2" : "\u25BC"}
                        </th>
                        <th className="px-4 py-3 text-white font-bold text-xs uppercase tracking-wider w-[130px]">
                          Type
                        </th>
                        <th className="px-4 py-3 text-white font-bold text-xs uppercase tracking-wider w-[170px]">
                          Component
                        </th>
                        <th className="px-4 py-3 text-white font-bold text-xs uppercase tracking-wider w-[150px]">
                          Issue
                        </th>
                        <th className="px-4 py-3 text-white font-bold text-xs uppercase tracking-wider min-w-[300px]">
                          Title
                        </th>
                      </tr>
                    </thead>
                    <tbody>
                      {paginatedRows.map((row, idx) => (
                        <tr
                          key={row.id}
                          data-row
                          className={`border-b border-white/5 transition-all duration-200 hover:bg-white/[0.08] hover:-translate-y-px hover:shadow-md ${
                            idx % 2 === 0 ? "bg-white/[0.02]" : ""
                          }`}
                        >
                          <td
                            data-field="priority"
                            className="px-4 py-3 text-white/90"
                          >
                            <span
                              title={fetchTitle(
                                (row.priority as string) || "6",
                              )}
                              className={`badge bg-secondary priority-${row.priority}`}
                            >
                              {row.priority && row.priority !== "6"
                                ? `P${row.priority}`
                                : "P?"}
                            </span>
                          </td>
                          <td
                            data-field="type"
                            className="px-4 py-3 text-white/90"
                          >
                            {row.type || "Hidden"}
                          </td>
                          <td
                            data-field="component"
                            className="px-4 py-3 text-white/90"
                          >
                            {row.component || ""}
                          </td>
                          <td data-field="id" className="px-4 py-3">
                            <a
                              target="_blank"
                              rel="noopener noreferrer"
                              href={String(row.link || "")}
                              className="issue-link"
                            >
                              {row.id}
                            </a>
                          </td>
                          <td
                            data-field="title"
                            className="px-4 py-3 text-white/90 break-words"
                          >
                            {row.title}
                          </td>
                        </tr>
                      ))}
                      {paginatedRows.length === 0 && (
                        <tr>
                          <td
                            colSpan={5}
                            className="px-4 py-8 text-center text-white/60"
                          >
                            No results found
                          </td>
                        </tr>
                      )}
                    </tbody>
                  </table>
                </div>

                {/* Pagination */}
                <div className="flex items-center justify-between gap-4 mt-4 bg-[#231146]/30 rounded-lg border border-white/[0.08] p-3 shadow-md text-white/85">
                  <div className="flex items-center gap-2 text-sm">
                    <span>Rows per page:</span>
                    <select
                      value={pageSize}
                      onChange={(e) => {
                        setPageSize(Number(e.target.value));
                        setPage(0);
                      }}
                      className="bg-[#231146]/60 text-white/85 border border-white/10 rounded-md px-2 py-1 text-sm focus:outline-none focus:border-pink"
                    >
                      {[20, 50, 75].map((size) => (
                        <option key={size} value={size}>
                          {size}
                        </option>
                      ))}
                    </select>
                  </div>
                  <div className="flex items-center gap-3 text-sm">
                    <span>
                      {totalRows > 0
                        ? `${safePage * pageSize + 1}\u2013${Math.min((safePage + 1) * pageSize, totalRows)} of ${totalRows}`
                        : "0 of 0"}
                    </span>
                    <button
                      onClick={() => setPage((p) => Math.max(0, p - 1))}
                      disabled={safePage === 0}
                      className="px-2 py-1 rounded bg-[#231146]/40 border border-white/5 hover:bg-pink/15 disabled:opacity-40 disabled:cursor-not-allowed transition-all"
                    >
                      &lsaquo;
                    </button>
                    <button
                      onClick={() =>
                        setPage((p) => Math.min(totalPages - 1, p + 1))
                      }
                      disabled={safePage >= totalPages - 1}
                      className="px-2 py-1 rounded bg-[#231146]/40 border border-white/5 hover:bg-pink/15 disabled:opacity-40 disabled:cursor-not-allowed transition-all"
                    >
                      &rsaquo;
                    </button>
                  </div>
                </div>
              </>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default ReleaseNotesRender;
